'use client';

import { useState, useEffect, useCallback } from 'react';
import { getToken } from '@/lib/api-client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Plus, Trash2, Pencil, X, Loader2, Tag, GripVertical } from 'lucide-react';
interface Category {
  id: string;
  name: string;
  sort_order: number;
  created_at: string;
}
export default function AdminCategoriesPage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formName, setFormName] = useState('');
  const [formSort, setFormSort] = useState('0');

  // Edit state
  const [editCat, setEditCat] = useState<Category | null>(null);
  const [editName, setEditName] = useState('');
  const [editSort, setEditSort] = useState('0');
  const fetchCategories = useCallback(async () => {
    const token = getToken();
    if (!token) return;
    const res = await fetch('/api/admin/categories', {
      headers: {
        'x-session': token
      }
    });
    if (res.ok) {
      const data = await res.json();
      setCategories(data.categories || []);
    }
    setLoading(false);
  }, []);
  useEffect(() => {
    fetchCategories();
  }, [fetchCategories]);
  const handleAdd = async () => {
    if (!formName.trim()) return;
    setSaving(true);
    const token = getToken();
    if (!token) {
      alert('请先登录');
      setSaving(false);
      return;
    }
    try {
      const res = await fetch('/api/admin/categories', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-session': token
        },
        body: JSON.stringify({
          name: formName.trim(),
          sort_order: parseInt(formSort) || 0
        })
      });
      if (res.ok) {
        setShowAdd(false);
        setFormName('');
        setFormSort('0');
        fetchCategories();
      } else {
        const data = await res.json();
        alert(data.error || '添加失败');
      }
    } finally {
      setSaving(false);
    }
  };
  const handleEdit = async () => {
    if (!editCat) return;
    const token = getToken();
    if (!token) return;
    const res = await fetch('/api/admin/categories', {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'x-session': token
      },
      body: JSON.stringify({
        id: editCat.id,
        name: editName.trim(),
        sort_order: parseInt(editSort) || 0
      })
    });
    if (res.ok) {
      setEditCat(null);
      fetchCategories();
    } else {
      const data = await res.json();
      alert(data.error || '修改失败');
    }
  };
  const handleDelete = async (cat: Category) => {
    if (!confirm(`确定删除分类「${cat.name}」？`)) return;
    const token = getToken();
    if (!token) return;
    const res = await fetch(`/api/admin/categories?id=${cat.id}`, {
      method: 'DELETE',
      headers: {
        'x-session': token
      }
    });
    if (res.ok) {
      const data = await res.json();
      if (data.affectedTools > 0) {
        alert(`分类已删除。注意：${data.affectedTools} 个工具仍引用「${data.categoryName}」，建议手动更新。`);
      }
      fetchCategories();
    } else {
      const data = await res.json().catch(() => ({}));
      alert(data.error || '删除失败');
    }
  };
  if (loading) {
    return <div data-inspector-line="111" data-inspector-column="6" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex items-center justify-center py-20">
        <Loader2 data-inspector-line="112" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-6 h-6 animate-spin text-gray-400" />
      </div>;
  }
  return <div data-inspector-line="118" data-inspector-column="4" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="space-y-6">
      <div data-inspector-line="119" data-inspector-column="6" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex items-center justify-between">
        <div data-inspector-line="120" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx">
          <h1 data-inspector-line="121" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-xl font-semibold text-gray-900">分类管理</h1>
          <p data-inspector-line="122" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-sm text-gray-500 mt-1">管理工具的显示分类，用户端将按分类筛选工具</p>
        </div>
        <Button data-inspector-line="124" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" onClick={() => setShowAdd(true)} className="bg-blue-600 hover:bg-blue-700">
          <Plus data-inspector-line="125" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 mr-1" /> 添加分类
        </Button>
      </div>

      {/* Add Form */}
      {showAdd && <Card data-inspector-line="131" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="border-blue-200 bg-blue-50/30">
          <CardHeader data-inspector-line="132" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="pb-3">
            <div data-inspector-line="133" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex items-center justify-between">
              <CardTitle data-inspector-line="134" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-base">添加分类</CardTitle>
              <button data-inspector-line="135" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" onClick={() => {
            setShowAdd(false);
            setFormName('');
            setFormSort('0');
          }} className="text-gray-400 hover:text-gray-600">
                <X data-inspector-line="136" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4" />
              </button>
            </div>
          </CardHeader>
          <CardContent data-inspector-line="140" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="space-y-4">
            <div data-inspector-line="141" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="grid grid-cols-2 gap-4">
              <div data-inspector-line="142" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="space-y-1.5">
                <label data-inspector-line="143" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-sm font-medium">分类名称 *</label>
                <Input data-inspector-line="144" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" value={formName} onChange={e => setFormName(e.target.value)} placeholder="如：写作、翻译、编程" />
              </div>
              <div data-inspector-line="146" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="space-y-1.5">
                <label data-inspector-line="147" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-sm font-medium">排序权重</label>
                <Input data-inspector-line="148" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" type="number" min="0" value={formSort} onChange={e => setFormSort(e.target.value)} />
              </div>
            </div>
            <div data-inspector-line="151" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex gap-2 pt-2">
              <Button data-inspector-line="152" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" onClick={handleAdd} disabled={saving || !formName.trim()} className="bg-blue-600 hover:bg-blue-700">
                {saving ? <Loader2 data-inspector-line="153" data-inspector-column="26" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 mr-1 animate-spin" /> : <Plus data-inspector-line="153" data-inspector-column="78" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 mr-1" />}
                确认添加
              </Button>
              <Button data-inspector-line="156" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" variant="outline" onClick={() => {
            setShowAdd(false);
            setFormName('');
            setFormSort('0');
          }}>取消</Button>
            </div>
          </CardContent>
        </Card>}

      {/* Categories List */}
      {categories.length === 0 ? <Card data-inspector-line="164" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx">
          <CardContent data-inspector-line="165" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="py-12 text-center text-gray-500">
            暂无分类，点击上方「添加分类」开始创建
          </CardContent>
        </Card> : <div data-inspector-line="170" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="grid gap-3">
          {categories.map(cat => <Card data-inspector-line="172" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" key={cat.id} className="hover:shadow-sm transition-shadow">
              <CardContent data-inspector-line="173" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="py-3 px-4">
                <div data-inspector-line="174" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex items-center gap-3">
                  <GripVertical data-inspector-line="175" data-inspector-column="18" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 text-gray-300 shrink-0" />
                  <div data-inspector-line="176" data-inspector-column="18" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex-1 min-w-0 flex items-center gap-3">
                    <Tag data-inspector-line="177" data-inspector-column="20" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 text-blue-500 shrink-0" />
                    <span data-inspector-line="178" data-inspector-column="20" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="font-medium text-gray-900">{cat.name}</span>
                    <Badge data-inspector-line="179" data-inspector-column="20" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" variant="outline" className="text-xs shrink-0">排序: {cat.sort_order}</Badge>
                  </div>
                  <div data-inspector-line="181" data-inspector-column="18" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex items-center gap-1 shrink-0">
                    <Button data-inspector-line="182" data-inspector-column="20" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" variant="ghost" size="sm" onClick={() => {
                setEditCat(cat);
                setEditName(cat.name);
                setEditSort(String(cat.sort_order));
              }} title="编辑">
                      <Pencil data-inspector-line="188" data-inspector-column="22" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4 text-blue-600" />
                    </Button>
                    <Button data-inspector-line="190" data-inspector-column="20" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" variant="ghost" size="sm" onClick={() => handleDelete(cat)} className="text-red-600 hover:text-red-700 hover:bg-red-50">
                      <Trash2 data-inspector-line="196" data-inspector-column="22" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>)}
        </div>}

      {/* Edit Dialog */}
      {editCat && <div data-inspector-line="208" data-inspector-column="8" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div data-inspector-line="209" data-inspector-column="10" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="bg-white rounded-lg p-6 w-full max-w-sm mx-4">
            <h3 data-inspector-line="210" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="text-lg font-semibold mb-4">编辑分类</h3>
            <div data-inspector-line="211" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="space-y-4">
              <div data-inspector-line="212" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx">
                <label data-inspector-line="213" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="block text-sm font-medium mb-1">分类名称</label>
                <Input data-inspector-line="214" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" value={editName} onChange={e => setEditName(e.target.value)} />
              </div>
              <div data-inspector-line="216" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx">
                <label data-inspector-line="217" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="block text-sm font-medium mb-1">排序权重</label>
                <Input data-inspector-line="218" data-inspector-column="16" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" type="number" min="0" value={editSort} onChange={e => setEditSort(e.target.value)} />
              </div>
            </div>
            <div data-inspector-line="221" data-inspector-column="12" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" className="flex justify-end gap-2 mt-6">
              <Button data-inspector-line="222" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" variant="outline" onClick={() => setEditCat(null)}>取消</Button>
              <Button data-inspector-line="223" data-inspector-column="14" data-inspector-relative-path="src\\app\\admin\\categories\\page.tsx" onClick={handleEdit} disabled={!editName.trim()}>保存</Button>
            </div>
          </div>
        </div>}
    </div>;
}